        case 'MARKET': return LAB_3_MARKET
        case 'STRATEGY': return LAB_4_STRATEGY
        case 'TECH': return LAB_5_TECH
        case 'BUSINESS': return LAB_6_BUSINESS
        case 'FOUNDER': return LAB_7_FOUNDER
    }
}

export function getLabNumber(labType: LabType): number {
    switch (labType) {
        case 'DISCOVERY': return 1
